from collections import defaultdict
import heapq

class Solution:
    def isPossible(self, nums: List[int]) -> bool:
        chains = defaultdict(list)
        for v in nums:
            if chains[v - 1]:
                length = heapq.heappop(chains[v - 1])
                heapq.heappush(chains[v], length + 1)
            else:
                heapq.heappush(chains[v], 1)
        for key in chains:
            for length in chains[key]:
                if length < 3:
                    return False
        return True
